fn solve(s: String, k: i64) -> String {
    let mut result = Vec::new();
    for c in s.chars() {
        match c {
            'a'..='z' => result.push(c),
            '*' => {
                if !result.is_empty() {
                    result.pop();
                }
            },
            '#' => {
                let mut clone = result.clone();
                result.extend(clone);
            },
            '%' => {
                result.reverse();
            },
            _ => {}
        }
    }
    if k < 0 || k >= result.len() as i64 {
        return String::from(".");
    }
    let char = result[k as usize];
    String::from(char)
}
